CREATE TABLE "video2"."process_isobmff" ("id" uuid NOT NULL DEFAULT gen_random_uuid(), "created_at" timestamptz NOT NULL DEFAULT now(), "completed_at" timestamptz, "failed_at" timestamptz NOT NULL, "unprocessed_file_id" uuid NOT NULL, "api_key_id" uuid NOT NULL, PRIMARY KEY ("id") , FOREIGN KEY ("unprocessed_file_id") REFERENCES "video2"."unprocessed_files"("id") ON UPDATE restrict ON DELETE restrict, FOREIGN KEY ("api_key_id") REFERENCES "identity"."api_keys"("id") ON UPDATE restrict ON DELETE restrict);COMMENT ON TABLE "video2"."process_isobmff" IS E'Process an unprocessed file as an isobmff_file';
CREATE EXTENSION IF NOT EXISTS pgcrypto;
